      setPonds(pondsRes?.data?.data || []);
    } catch (err) {
      pushToast({
        title: "Thất bại",
        message: err?.response?.data?.message || 'KhÃ´ng táº£i Ä‘Æ°á»£c dá»¯ liá»‡u cÃ´ng viá»‡c',
        type: "error"
      });
    } finally {
      setLoading(false);
    }
  };
  const staffOptions = useMemo(() => {
    return staffList.map(staff => ({
      id: staff.user_id,
      name: staff.full_name || staff.username
    }));
  }, [staffList]);
  const seasonOptions = useMemo(() => {
    return seasons.map(season => ({
      id: season.season_id,
      name: `${season.season_name || `MÃ¹a vá»¥ ${season.season_id}`} - Ao ${season.pond_id}`,
      pondId: season.pond_id
    }));
  }, [seasons]);
  const filteredSeasonOptions = useMemo(() => {
    if (!form.pond_id) {
      return seasonOptions;
    }
    return seasonOptions.filter(season => String(season.pondId) === String(form.pond_id));
  }, [seasonOptions, form.pond_id]);
  const pondOptions = useMemo(() => {
    return ponds.map(pond => ({
      id: pond.pond_id,
      code: pond.pond_code,
      name: pond.pond_name
    }));
  }, [ponds]);
  const getStaffName = id => {
    if (!id) return '-';
    const found = staffOptions.find(s => String(s.id) === String(id));
    return found ? found.name : '-';
  };
  const getSeasonName = id => {
    if (!id) return '-';
